module accu
(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output reg valid_out,
    output [9:0] data_out
);

reg [7:0] data_in_reg [3:0];
reg [9:0] data_out_reg;
reg [1:0] cnt;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 0;
        valid_out <= 0;
        data_out_reg <= 0;
        for (int i = 0; i < 4; i++) begin
            data_in_reg[i] <= 0;
        end
    end
    else begin
        if (valid_in) begin
            data_in_reg[cnt] <= data_in;
            cnt <= cnt + 1;
            if (cnt == 2'b11) begin
                data_out_reg <= data_in_reg[0] + data_in_reg[1] + data_in_reg[2] + data_in_reg[3];
                valid_out <= 1;
                cnt <= 0;
            end
            else begin
                valid_out <= 0;
            end
        end
        else begin
            valid_out <= 0;
        end
    end
end

assign data_out = data_out_reg;

endmodule
